import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { toggleWishlist } from '../services/api';
import { toast } from 'react-toastify';

const Stars = ({ rating }) => '★'.repeat(Math.round(rating || 0)) + '☆'.repeat(5 - Math.round(rating || 0));

const ProductCard = ({ product }) => {
  const { addItem } = useCart();
  const { user } = useAuth();
  const BACKEND_URL = "http://localhost:5000";

  // Debug: Log the product data to see image structure
  console.log('ProductCard - Product data:', product);
  console.log('ProductCard - Images:', product.images);
  console.log('ProductCard - First image:', product.images?.[0]);

  const handleAddToCart = () => {
    addItem(product);
    toast.success('Added to cart!');
  };

  const handleWishlist = async () => {
    if (!user) return toast.info('Please login to save to wishlist');
    try {
      await toggleWishlist(product._id);
      toast.success('Wishlist updated!');
    } catch { toast.error('Failed to update wishlist'); }
  };

  // FIXED: Better image URL handling
  const getImageUrl = () => {
    const firstImage = product.images?.[0];
    console.log('ProductCard - Raw firstImage:', firstImage);

    if (!firstImage) {
      console.log('ProductCard - No image found, using placeholder');
      return `https://via.placeholder.com/400x500?text=${encodeURIComponent(product.name || 'No Image')}`;
    }

    // Handle if firstImage is an object with url property
    if (typeof firstImage === 'object' && firstImage.url) {
      console.log('ProductCard - Image is object with url:', firstImage.url);
      if (firstImage.url.startsWith('http') || firstImage.url.startsWith('data:')) {
        return firstImage.url;
      }
      return `${BACKEND_URL}${firstImage.url.startsWith('/') ? '' : '/'}${firstImage.url}`;
    }

    // Handle if firstImage is a string
    if (typeof firstImage === 'string') {
      console.log('ProductCard - Image is string:', firstImage);
      if (firstImage.startsWith('http') || firstImage.startsWith('data:')) {
        return firstImage;
      }
      return `${BACKEND_URL}${firstImage.startsWith('/') ? '' : '/'}${firstImage}`;
    }

    console.log('ProductCard - Unknown image format, using placeholder');
    return `https://via.placeholder.com/400x500?text=${encodeURIComponent(product.name || 'No Image')}`;
  };

  const img = getImageUrl();
  const price = product.discountPrice > 0 ? product.discountPrice : product.price;

  return (
    <div className="product-card">
      <div className="card-img-wrap">
        <Link to={`/products/${product._id}`}>
          <img 
            src={img} 
            alt={product.name} 
            loading="lazy"
            onError={(e) => {
              console.error('ProductCard - Image failed to load:', img);
              e.target.src = `https://via.placeholder.com/400x500?text=${encodeURIComponent(product.name || 'No Image')}`;
            }}
            onLoad={() => console.log('ProductCard - Image loaded successfully:', img)}
          />
        </Link>
        <button className="wishlist-btn" onClick={handleWishlist} title="Add to wishlist">♡</button>
        {product.discountPrice > 0 && (
          <span className="badge-sale">-{Math.round((1 - product.discountPrice / product.price) * 100)}%</span>
        )}
      </div>
      <div className="card-body">
        <p className="card-category">{product.category}</p>
        <Link to={`/products/${product._id}`}><h3 className="card-title">{product.name}</h3></Link>
        <div className="card-rating">
          <span className="stars"><Stars rating={product.rating} /></span>
          <span className="review-count">({product.numReviews || 0})</span>
        </div>
        <div className="card-price">
          <span className="price-current">PKR {price.toLocaleString()}</span>
          {product.discountPrice > 0 && <span className="price-original">PKR {product.price.toLocaleString()}</span>}
        </div>
        <button className="btn-add-cart" onClick={handleAddToCart} disabled={product.stock === 0}>
          {product.stock === 0 ? 'Out of Stock' : 'Add to Cart'}
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
